#!/bin/bash
# HERCOSSNUX NPU - Fase A, Paso 14 (Layer 5): integracion AXI completa.
#
# Une el npu_top verificado (Pasos 1-11), el motor DMA (Paso 12) y el esclavo
# AXI4 de registros (Paso 13) en npu_axi_top, con el patron doorbell:
#
#   PS escribe pesos e imagen en DDR
#   PS escribe CTRL.load_weights -> el core trae W1,B1,W2,B2,W3,B3 por DMA
#   PS escribe CTRL.start        -> trae la imagen, infiere, escribe resultado
#   PS lee STATUS.done y la clase en STATUS bits 7:4
#
# El demultiplexor traduce el flujo plano de bytes del DMA a los puertos
# we/addr/data del nucleo. Los bias son int32 y se reensamblan en little
# endian a partir de 4 bytes consecutivos.
#
# CRITERIO: SIG_CLASE = 0x6084FD2A, la misma firma congelada del Paso 7, con
# los datos llegando desde DDR en lugar de por puertos.
#
# ACTUALIZA tb/axi_ddr_model.vhd (anade puerto de precarga).
# Requiere: ghdl 4.1.0 --std=08. Requiere los Pasos 1-13.
# Linea esperada al final:
# NPU PASO14 OK INTEGRACION AXI SIG_CLASE=0x6084FD2A
(
set -e
DIR="$HOME/vhdl_repo/IP_Cores/NPU"
for f in rtl/npu_axi_slave.vhd rtl/npu_dma.vhd rtl/npu_top.vhd; do
  if [ ! -f "$DIR/$f" ]; then
    echo "FALLO: falta $f (corre primero los Pasos 1-13)"; exit 1
  fi
done
mkdir -p "$DIR/rtl" "$DIR/tb" "$DIR/vec"
base64 -d << "EOF" > "$DIR/rtl/npu_axi_top.vhd"

EOF
base64 -d << "EOF" > "$DIR/tb/tb_npu_axi.vhd"

EOF
base64 -d << "EOF" > "$DIR/tb/axi_ddr_model.vhd"

EOF
base64 -d << "EOF" > "$DIR/gen_ddr_image.py"

EOF
base64 -d << "EOF" > "$DIR/run_axi_int.sh"

EOF
chmod +x "$DIR/run_axi_int.sh"
cd "$DIR"
bash run_axi_int.sh
)
